#include <cuda.h>

__global__
__launch_bounds__(256) void fused_matmul(const __grid_constant__ CUtensorMap A_tma, const __grid_constant__ CUtensorMap B_tma, float* C) {
    extern __shared__ __align__(128) char dsmem[];
    float*smem=(float*)dsmem;
    uint64_t*mbar=(uint64_t*)(dsmem+2*6144*4);
    const int as0=(int)__cvta_generic_to_shared(&smem[0]);
    const int bs0=(int)__cvta_generic_to_shared(&smem[2048]);
    const int as1=(int)__cvta_generic_to_shared(&smem[6144]);
    const int bs1=(int)__cvta_generic_to_shared(&smem[6144+2048]);
    const int mb0=(int)__cvta_generic_to_shared(&mbar[0]);
    const int mb1=(int)__cvta_generic_to_shared(&mbar[1]);
    int tid=threadIdx.y*32+threadIdx.x;
    int tr=threadIdx.y*8,tc=threadIdx.x*4;
    // CTA swizzle: rasterize in groups of SWIZ row-blocks for L2 A-tile reuse
    const int SWIZ=8;
    int ntx=(N+127)/128;
    int nty=(M+63)/64;
    int pid=blockIdx.x+blockIdx.y*gridDim.x;
    int grp=pid/(ntx*SWIZ);
    int rem=pid%(ntx*SWIZ);
    int by_s=grp*SWIZ+rem%SWIZ;
    int bx_s=rem/SWIZ;
    if(by_s>=nty||bx_s>=ntx)return;
    int bm=by_s*64,bn=bx_s*128;

    if(tid==0){asm volatile("mbarrier.init.shared::cta.b64 [%0],%1;"::"r"(mb0),"r"(1));asm volatile("mbarrier.init.shared::cta.b64 [%0],%1;"::"r"(mb1),"r"(1));asm volatile("fence.mbarrier_init.release.cluster;");}
    __syncthreads();
    float c00=0,c01=0,c02=0,c03=0,c10=0,c11=0,c12=0,c13=0,c20=0,c21=0,c22=0,c23=0,c30=0,c31=0,c32=0,c33=0,c40=0,c41=0,c42=0,c43=0,c50=0,c51=0,c52=0,c53=0,c60=0,c61=0,c62=0,c63=0,c70=0,c71=0,c72=0,c73=0;
    const int bytes=24576;
    int p0=0,p1=0,nt=K/32;
    if(nt>0&&tid==0){asm volatile("mbarrier.arrive.expect_tx.release.cta.shared::cta.b64 _,[%0],%1;"::"r"(mb0),"r"(bytes):"memory");asm volatile("cp.async.bulk.tensor.2d.shared::cta.global.mbarrier::complete_tx::bytes [%0],[%1,{%2,%3}],[%4];"::"r"(as0),"l"(&A_tma),"r"(0),"r"(bm),"r"(mb0):"memory");asm volatile("cp.async.bulk.tensor.2d.shared::cta.global.mbarrier::complete_tx::bytes [%0],[%1,{%2,%3}],[%4];"::"r"(bs0),"l"(&B_tma),"r"(bn),"r"(0),"r"(mb0):"memory");}
    for(int t=0;t<nt;t++){
        int s=t%2;int cm=s==0?mb0:mb1;int cp=s==0?p0:p1;
        int nm=s==0?mb1:mb0;int na=s==0?as1:as0;int nb=s==0?bs1:bs0;
        asm volatile("{\n\t.reg .pred P1;\n\tLW:\n\tmbarrier.try_wait.parity.acquire.cta.shared::cta.b64 P1,[%0],%1,%2;\n\t@P1 bra.uni LD;\n\tbra.uni LW;\n\tLD:\n\t}"::"r"(cm),"r"(cp),"r"(0xffffffff));
        if(s==0)p0^=1;else p1^=1;
        if(tid==0&&t+1<nt){int nk=(t+1)*32;asm volatile("mbarrier.arrive.expect_tx.release.cta.shared::cta.b64 _,[%0],%1;"::"r"(nm),"r"(bytes):"memory");asm volatile("cp.async.bulk.tensor.2d.shared::cta.global.mbarrier::complete_tx::bytes [%0],[%1,{%2,%3}],[%4];"::"r"(na),"l"(&A_tma),"r"(nk),"r"(bm),"r"(nm):"memory");asm volatile("cp.async.bulk.tensor.2d.shared::cta.global.mbarrier::complete_tx::bytes [%0],[%1,{%2,%3}],[%4];"::"r"(nb),"l"(&B_tma),"r"(bn),"r"(nk),"r"(nm):"memory");}
        float*cas=&smem[s*6144];float*cbs=&smem[s*6144+2048];
        #pragma unroll
        for(int kk=0;kk<32;kk++){
                float b0=cbs[kk*128+tc],b1=cbs[kk*128+tc+1],b2=cbs[kk*128+tc+2],b3=cbs[kk*128+tc+3];
                float a0=cas[(tr+0)*32+kk];
                c00+=a0*b0;c01+=a0*b1;c02+=a0*b2;c03+=a0*b3;
                float a1=cas[(tr+1)*32+kk];
                c10+=a1*b0;c11+=a1*b1;c12+=a1*b2;c13+=a1*b3;
                float a2=cas[(tr+2)*32+kk];
                c20+=a2*b0;c21+=a2*b1;c22+=a2*b2;c23+=a2*b3;
                float a3=cas[(tr+3)*32+kk];
                c30+=a3*b0;c31+=a3*b1;c32+=a3*b2;c33+=a3*b3;
                float a4=cas[(tr+4)*32+kk];
                c40+=a4*b0;c41+=a4*b1;c42+=a4*b2;c43+=a4*b3;
                float a5=cas[(tr+5)*32+kk];
                c50+=a5*b0;c51+=a5*b1;c52+=a5*b2;c53+=a5*b3;
                float a6=cas[(tr+6)*32+kk];
                c60+=a6*b0;c61+=a6*b1;c62+=a6*b2;c63+=a6*b3;
                float a7=cas[(tr+7)*32+kk];
                c70+=a7*b0;c71+=a7*b1;c72+=a7*b2;c73+=a7*b3;
        }
        __syncthreads();
    }
    #if (M % 64 == 0 && N % 128 == 0)
    #define W(r,v0,v1,v2,v3) {{int gr=bm+tr+(r);int gc=bn+tc;float*Cout=C; Cout[gr*N+gc]=v0;Cout[gr*N+gc+1]=v1;Cout[gr*N+gc+2]=v2;Cout[gr*N+gc+3]=v3;}}
    #else
    #define W(r,v0,v1,v2,v3) {{int gr=bm+tr+(r);if(gr<M){{int gc=bn+tc;float*Cout=C; if(gc<N)Cout[gr*N+gc]=v0;if(gc+1<N)Cout[gr*N+gc+1]=v1;if(gc+2<N)Cout[gr*N+gc+2]=v2;if(gc+3<N)Cout[gr*N+gc+3]=v3;}}}}
    #endif
        W(0,c00,c01,c02,c03)
        W(1,c10,c11,c12,c13)
        W(2,c20,c21,c22,c23)
        W(3,c30,c31,c32,c33)
        W(4,c40,c41,c42,c43)
        W(5,c50,c51,c52,c53)
        W(6,c60,c61,c62,c63)
        W(7,c70,c71,c72,c73)
}
